  .minimal-shell { display: block; padding-bottom: calc(78px + env(safe-area-inset-bottom)); }
  .minimal-sidebar { min-height: auto; border-right: 0px; border-bottom: 1px solid rgba(255, 255, 255, 0.06); }
  .minimal-brand { min-height: 58px; padding-inline: 16px; }
  .minimal-nav { display: none; }
  .minimal-nav p { display: none; }
  .minimal-nav-item { width: auto; flex: 0 0 auto; padding-inline: 12px; white-space: nowrap; }
  .minimal-header { min-height: auto; flex-wrap: wrap; padding: 14px 16px; }
  .minimal-search { width: 100%; order: 2; }
  .minimal-actions { width: 100%; justify-content: space-between; gap: 8px; }
  .minimal-primary { padding-inline: 12px; }
  .minimal-icon { display: none; }
  .minimal-user { max-width: 104px; overflow: hidden; white-space: nowrap; }
  .minimal-page { padding: 18px 16px 28px; }
