@media (max-width: 460px) {
  .minimal-actions { flex-wrap: wrap; }
  .minimal-primary, .minimal-status, .minimal-user { flex: 1 1 auto; }
  .minimal-stats { grid-template-columns: 1fr; }
}

@media (max-width: 1180px) {
  .app-dashboard { grid-template-columns: 220px minmax(0px, 1fr); }
  .dashboard-grid, .kanban-board { grid-template-columns: 1fr; }
  .stats-grid { grid-template-columns: repeat(2, minmax(0px, 1fr)); }
  .filter-bar, .board-toolbar { grid-template-columns: 1fr 1fr; }
  .stats-panels, .timeline-layout, .ai-suggest-grid, .settings-layout { grid-template-columns: 1fr; }
}

@media (max-width: 820px) {
  .auth-shell { grid-template-columns: 1fr; padding: 16px; }
  .auth-brand-panel { min-height: auto; padding: 24px; }
  .auth-brand-panel h1 { font-size: 34px; }
  .app-dashboard { display: block; padding-bottom: 78px; }
  .sidebar { position: fixed; z-index: 50; transform: translateX(-100%); transition: transform 180ms; }
  .sidebar.open { transform: translateX(0px); }
  .mobile-overlay { position: fixed; inset: 0px; z-index: 45; display: block; border: 0px; background: rgba(15, 23, 42, 0.28); }
  .mobile-menu { display: inline-flex; }
  .top-header { min-height: auto; padding: 12px 14px; }
  .header-search { flex: 1 1 0%; }
  .header-actions .primary-button { display: none; }
  .header-actions .user-pill, .header-actions .icon-button[aria-label="通知"] { display: none; }
  .page-content { padding: 16px; }
  .welcome-panel, .section-title, .page-heading, .table-footer, .drawer-header { align-items: stretch; flex-direction: column; }
  .stats-grid, .filter-bar, .board-toolbar, .drawer-fields, .preview-grid, .form-grid { grid-template-columns: 1fr; }
  .preview-actions .primary-button { margin-left: 0px; }
  .calendar-grid { grid-template-columns: 1fr; }
  .calendar-controls, .range-tabs { flex-wrap: nowrap; margin-inline: -16px; padding-inline: 16px; overflow-x: auto; }
  .calendar-day { border-right: 0px; border-bottom: 1px solid var(--line); }
  .drawer { width: 100vw; }
  .modal-backdrop { place-items: end center; padding: 10px; }
